import SwiftUI
import UIKit

struct CompanyLogoView: View {
    var maxHeight: CGFloat = 145

    var body: some View {
        VStack(spacing: 8) {
            if let image = UIImage.companyLogo {
                Image(uiImage: image)
                    .resizable()
                    .scaledToFit()
                    .frame(maxHeight: maxHeight)
                    .padding(14)
                    .frame(maxWidth: .infinity)
                    .background(
                        RoundedRectangle(cornerRadius: 24)
                            .fill(.white)
                            .shadow(color: .black.opacity(0.12), radius: 14, x: 0, y: 6)
                    )
            } else {
                Text("บริษัท ธัญญวิชญ์ จำกัด")
                    .font(.title.bold())
                    .frame(maxWidth: .infinity)
                    .padding()
                    .background(.thinMaterial)
                    .clipShape(RoundedRectangle(cornerRadius: 24))
            }
        }
    }
}

extension UIImage {
    static var companyLogo: UIImage? {
        let embedded = ""
        if let data = Data(base64Encoded: embedded),
           let image = UIImage(data: data) {
            return image
        }

        if let url = Bundle.main.url(forResource: "company_logo", withExtension: "png", subdirectory: "Resources"),
           let data = try? Data(contentsOf: url),
           let image = UIImage(data: data) {
            return image
        }

        if let url = Bundle.main.url(forResource: "company_logo", withExtension: "png"),
           let data = try? Data(contentsOf: url),
           let image = UIImage(data: data) {
            return image
        }

        return nil
    }
}
